654→    /**
655→     * Retries a dependency satisfaction operation up to DEPEND_MAX_RETRIES times with exponential
656→     * backoff (100ms, 200ms, 400ms).
657→     *
658→     * Dependency satisfaction is critical — a transient failure (e.g. connection pool exhaustion)
659→     * can leave downstream frames permanently stuck in DEPEND state.
660→     */
661→    private void satisfyDependsWithRetry(Runnable operation, String entityDesc, String jobName,
662→            String jobId) {
663→        for (int attempt = 1; attempt <= DEPEND_MAX_RETRIES; attempt++) {
664→            try {
665→                operation.run();
666→                return;
667→            } catch (Exception e) {
668→                // Ideally DataAccessException should be the target to be caught, but pool
669→                // exhaustion is not categorized as such.
670→                // Pool exhaustion throws CannotCreateTransactionException (TransactionException)
671→                // which can only be caught in this context as a general Exception
672→                if (attempt < DEPEND_MAX_RETRIES) {
673→                    // Exponential backoff: 100ms, 200ms, 400ms (bit-shift doubles each attempt)
674→                    long backoffMs = DEPEND_INITIAL_BACKOFF_MS * (1L << (attempt - 1));
675→                    logger.warn("Failed to satisfy depends on " + entityDesc + " in job " + jobName
676→                            + " (attempt " + attempt + "/" + DEPEND_MAX_RETRIES + "), retrying in "
677→                            + backoffMs + "ms: " + e);
678→                    try {
679→                        // I acknowledge sleeping within a threadpool is rarely a good idea as it
680→                        // blocks execution and can lead to backpressure. This sleep is only
681→                        // triggered when there are transient issues, so it is likely the following
682→                        // tasks would also fails. The worst case scenario is backing up the
683→                        // threadpool for 700ms, which is acceptable given the circumstances
684→                        Thread.sleep(backoffMs);
685→                    } catch (InterruptedException ie) {
686→                        Thread.currentThread().interrupt();
687→                        logger.error("Dependency Failure: Interrupted while retrying depends on "
688→                                + entityDesc + " in job " + jobName + " (id=" + jobId + "). "
689→                                + "Downstream frames may be stuck in DEPEND state.");
690→                        return;
691→                    }
692→                } else {
693→                    logger.error("Dependency Failure: Failed to satisfy depends on " + entityDesc
694→                            + " in job " + jobName + " (id=" + jobId + ") after "
695→                            + DEPEND_MAX_RETRIES + " attempts. "
696→                            + "Downstream frames may be stuck in DEPEND state. " + e);
697→                }
698→            }
699→        }
700→    }
