        assertFalse(jobManager.isLayerComplete(layer));

        JobDetail ujob = jobManager.findJobDetail(jobName);
        LayerDetail ulayer = layerDao.findLayerDetail(ujob, "test_layer");
        assertEquals(expected, ulayer.getMinimumMemory());
    }

